#define DUCKDB_EXTENSION_MAIN

#include "jq_extension.hpp"
#include "duckdb.hpp"
#include "duckdb/common/exception.hpp"
#include "duckdb/function/scalar_function.hpp"
#include <duckdb/parser/parsed_data/create_scalar_function_info.hpp>

extern "C" {
#include <jq.h>
#include <jv.h>
}

namespace duckdb {

void JqScalarFun(DataChunk &args, ExpressionState &state, Vector &result) {
	// TODO: invoke second (varchar) argument from &args as a jq filter,
	// pass each value from the first argument vector through the filter,
	// and copying each jq result into the result vector.
}

unique_ptr<FunctionData> JqScalarBind(ClientContext &context, ScalarFunction &bound_function, vector<unique_ptr<Expression>> &arguments) {
  // TODO: verify that the second argument (jq expression) is foldable into a string constant
}

static void LoadInternal(ExtensionLoader &loader) {
	// Register a scalar function
	auto jq_scalar_function =
	    ScalarFunction("jq", {LogicalType::JSON(), LogicalType::VARCHAR}, LogicalType::JSON(), JqScalarFun, JqScalarBind);

	loader.RegisterFunction(jq_scalar_function);
}

void JqExtension::Load(ExtensionLoader &loader) {
	LoadInternal(loader);
}

std::string JqExtension::Name() {
	return "jq";
}

std::string JqExtension::Version() const {
#ifdef EXT_VERSION_JQ
	return EXT_VERSION_JQ;
#else
	return "";
#endif
}

} // namespace duckdb

extern "C" {

DUCKDB_CPP_EXTENSION_ENTRY(jq, loader) {
	duckdb::LoadInternal(loader);
}
}

